module adder_32bit
(
    input [32:1] A,
    input [32:1] B,
    output [32:1] S,
    output C32
);

wire [32:0] carry;
assign carry[0] = 1'b0;

genvar i;
generate
    for (i = 0; i < 32; i = i + 1) begin
        assign {carry[i+1], S[i+1]} = A[i+1] + B[i+1] + carry[i];
    end
endgenerate

assign C32 = carry[32];

endmodule
